#[cfg(test)]
mod tests {
    use crate::facade::test_support::engine;
    use crate::{GoalKind, TaskStatus};

    #[test]
    fn facade_creates_progressive_handoff_chain() {
        let engine = engine();
        let goal = engine
            .define_goal(GoalKind::Objective, "Safe handoff", "serialize edits", None)
            .unwrap();
        let first = engine.create_task(&goal.id, "Edit first", "done").unwrap();
        let second = engine
            .create_task_after(&goal.id, "Edit second", "done", Some(first.id.clone()))
            .unwrap();

        assert_eq!(second.status, TaskStatus::Blocked);
        assert_eq!(second.blocked_by.as_deref(), Some(first.id.as_str()));
    }

    #[test]
    fn decompose_falls_back_to_single_task_without_llm() {
        let e = engine();
        let g = e
            .define_goal(
                GoalKind::Objective,
                "Add search",
                "Implement FTS search",
                None,
            )
            .unwrap();
        let tasks = e.decompose_goal(&g.id).unwrap();
        assert_eq!(tasks.len(), 1);
        assert!(tasks[0].title.contains("Add search"));
    }
}
